/**
 * @fileoverview GridTable Feature — infinite scroll mixin.
 *
 * Lazy-loaded when `infiniteScroll: {...}` is set in config.
 * Fetches the next page of data when the user scrolls near the bottom,
 * appending rows without replacing existing data.
 *
 * Config shape:
 *   infiniteScroll: {
 *     fetch: async (params) => ({ data: [...], hasMore: bool }),
 *     pageSize: 50,         // rows per fetch (default 50)
 *     threshold: 200,       // px from bottom to trigger (default 200)
 *   }
 *
 * The `fetch` callback receives:
 *   { page, pageSize, sort, filters }
 * and must return { data: Array<Object>, hasMore: boolean }.
 *
 * @module module/GridTable/features/infinitescroll
 */

import { rebuildDisplayList, rebuildOffsets } from '../state.js';

/**
 * Install infinite scroll onto a GridTable ctx bridge.
 * @param {object} ctx — shared context bridge
 */
export function installInfiniteScroll(ctx) {
    ctx._infiniteScrollInstalled = true;

    const cfg = ctx.config.infiniteScroll;
    if (!cfg || typeof cfg.fetch !== 'function') return;

    const pageSize  = cfg.pageSize  || 50;
    const threshold = cfg.threshold || 200;

    let page       = 1;
    let loading    = false;
    let hasMore    = true;
    let destroyed  = false;

    /**
     * Fetch next page and append to existing data.
     */
    const fetchNext = async () => {
        if (loading || !hasMore || destroyed) return;
        loading = true;
        ctx.container.addClass('is-data-loading');

        try {
            const params = {
                page,
                pageSize,
                sort: ctx.sortState
                    ? { column: ctx.sortState.column, direction: ctx.sortState.direction }
                    : null,
                filters: { ...ctx.filterValues },
            };

            const result = await cfg.fetch(params);
            if (destroyed) return;

            const rows = Array.isArray(result?.data) ? result.data : [];
            hasMore = result?.hasMore !== false && rows.length >= pageSize;

            if (rows.length > 0) {
                // Append to existing data without triggering full setData
                const startIdx = ctx.data.length;
                ctx.data.push(...rows);

                // Extend row heights
                const rh = ctx.rowHeight;
                for (let i = 0; i < rows.length; i++) {
                    ctx.rowHeights.push(rh);
                }

                // Rebuild display list and offsets
                rebuildDisplayList(ctx);
                rebuildOffsets(ctx);
                ctx.updateSpacer();
                ctx.scheduleRender(true);

                page++;
            }
        } catch (err) {
            if (typeof cfg.onError === 'function') cfg.onError(err);
        } finally {
            loading = false;
            if (!destroyed) ctx.container.removeClass('is-data-loading');
        }
    };

    /**
     * Check scroll position and trigger fetch if near bottom.
     */
    const checkScroll = () => {
        if (!ctx.viewport?.[0] || loading || !hasMore) return;
        const vp = ctx.viewport[0];
        const remaining = vp.scrollHeight - vp.scrollTop - vp.clientHeight;
        if (remaining < threshold) {
            fetchNext();
        }
    };

    // Listen to viewport scroll (uses existing signal for cleanup)
    ctx.viewport.on('scroll', checkScroll, { signal: ctx.signal, passive: true });

    /**
     * Reset infinite scroll state (e.g. after filter/sort change).
     */
    ctx.infiniteScrollReset = () => {
        page = 1;
        hasMore = true;
        loading = false;
        // Clear data and re-fetch from page 1
        ctx.data.length = 0;
        ctx.rowHeights.length = 0;
        ctx.displayList = [];
        ctx.rowOffsets = [0];
        ctx.updateSpacer();
        ctx.scheduleRender(true);
        fetchNext();
    };

    /**
     * Get infinite scroll status.
     */
    ctx.infiniteScrollStatus = () => ({
        page,
        loading,
        hasMore,
        totalLoaded: ctx.data.length,
    });

    // Cleanup
    ctx._infiniteScrollDestroy = () => {
        destroyed = true;
    };

    // Initial fetch
    fetchNext();
}

export default installInfiniteScroll;
